    public function getSourceContext(): Source
    {
        return new Source("{% extends 'base.html.twig' %}

{% block title %}Modifier seance - BioSync{% endblock %}

{% block body %}
<div class=\"app-layout\">
    {% include 'partials/_sidebar.html.twig' with {'active': 'sports'} %}

    <main class=\"main-content\">
        <div class=\"page-header\">
            <h1 class=\"page-title\">Modifier la seance</h1>
            <p class=\"page-subtitle\">{{ seance.nomSeance }}</p>
        </div>

        <div class=\"card\" style=\"max-width: 600px;\">
            {{ form_start(form) }}
                <div class=\"form-group\">
                    {{ form_label(form.nomSeance) }}
                    {{ form_widget(form.nomSeance) }}
                    {{ form_errors(form.nomSeance) }}
                </div>

                <div class=\"form-row\">
                    <div class=\"form-group\">
                        {{ form_label(form.dateSeance) }}
                        {{ form_widget(form.dateSeance) }}
                        {{ form_errors(form.dateSeance) }}
                    </div>

                    <div class=\"form-group\">
                        {{ form_label(form.heureDebut) }}
                        {{ form_widget(form.heureDebut) }}
                        {{ form_errors(form.heureDebut) }}
                    </div>
                </div>

                <div class=\"form-group\">
                    {{ form_label(form.dureeMinutes) }}
                    {{ form_widget(form.dureeMinutes) }}
                    {{ form_errors(form.dureeMinutes) }}
                </div>

                <div class=\"modal-footer\" style=\"margin-top: 2rem; padding-top: 1rem; border-top: 1px solid var(--gray-200);\">
                    <a href=\"{{ path('app_sports') }}\" class=\"btn btn-ghost\">Annuler</a>
                    <button type=\"submit\" class=\"btn btn-secondary\">Enregistrer</button>
                </div>
            {{ form_end(form) }}
        </div>
    </main>
</div>
{% endblock %}
", "sports/edit.html.twig", "C:\\biosync_new\\templates\\sports\\edit.html.twig");
